#include <hip/hip_runtime.h>
#include <cstdio>
#include <cstdlib>
#include <vector>
#include <algorithm>
#include <cstdint>

#define HIP_CHECK(cmd) do { hipError_t e = (cmd); if (e != hipSuccess) { fprintf(stderr, "HIP error %s\n", hipGetErrorString(e)); exit(1); } } while(0)

template<int VEC>
__global__ void stream_read(const float4* __restrict__ in,
                            float* __restrict__ sink,
                            unsigned long long n_vec) {
    const unsigned long long tid =
        (unsigned long long)blockIdx.x * blockDim.x + threadIdx.x;
    const unsigned long long stride =
        (unsigned long long)gridDim.x * blockDim.x;

    float accum = 0.0f;
    #pragma unroll 1
    for (unsigned long long i = tid; i < n_vec; i += stride * VEC) {
        float4 v[VEC];
        #pragma unroll
        for (int j = 0; j < VEC; ++j) {
            v[j] = in[i + j * stride];
        }
        #pragma unroll
        for (int j = 0; j < VEC; ++j) {
            accum += v[j].x + v[j].y + v[j].z + v[j].w;
        }
    }
    sink[tid] = accum;
}

int main(int argc, char** argv) {
    HIP_CHECK(hipSetDevice(0));
    int VEC = (argc > 2) ? atoi(argv[2]) : 1;
    unsigned long long gi = 1ULL << 30;
    unsigned long long buffer_bytes = (argc > 1) ? (gi * atoll(argv[1])) : (4ULL << 30);
    const unsigned long long n_vec = buffer_bytes / sizeof(float4);

    float4* d_in; float* d_sink;
    HIP_CHECK(hipMalloc(&d_in, (size_t)buffer_bytes));
    HIP_CHECK(hipMalloc(&d_sink, 4ULL << 20));
    HIP_CHECK(hipMemset(d_in, 0xab, (size_t)buffer_bytes));

    const int blocks = 1024, threads = 256;
    for (int i = 0; i < 10; ++i) {
        if (VEC == 1) hipLaunchKernelGGL((stream_read<1>), dim3(blocks), dim3(threads), 0, 0, d_in, d_sink, n_vec);
        else if (VEC == 2) hipLaunchKernelGGL((stream_read<2>), dim3(blocks), dim3(threads), 0, 0, d_in, d_sink, n_vec);
        else if (VEC == 4) hipLaunchKernelGGL((stream_read<4>), dim3(blocks), dim3(threads), 0, 0, d_in, d_sink, n_vec);
    }
    HIP_CHECK(hipDeviceSynchronize());

    const int N = 50;
    std::vector<float> t(N);
    hipEvent_t s, e;
    hipEventCreate(&s); hipEventCreate(&e);
    for (int i = 0; i < N; ++i) {
        hipEventRecord(s);
        if (VEC == 1) hipLaunchKernelGGL((stream_read<1>), dim3(blocks), dim3(threads), 0, 0, d_in, d_sink, n_vec);
        else if (VEC == 2) hipLaunchKernelGGL((stream_read<2>), dim3(blocks), dim3(threads), 0, 0, d_in, d_sink, n_vec);
        else if (VEC == 4) hipLaunchKernelGGL((stream_read<4>), dim3(blocks), dim3(threads), 0, 0, d_in, d_sink, n_vec);
        hipEventRecord(e);
    }
    HIP_CHECK(hipDeviceSynchronize());
    for (int i = 0; i < N; ++i) hipEventElapsedTime(&t[i], s, e);
    std::sort(t.begin(), t.end());
    float med = t[N/2];
    double bw = (double)buffer_bytes / (med * 1e-3) / 1e9;
    fprintf(stderr, "buffer=%.2f GiB  VEC=%d  median=%.4f ms  bw=%.2f GB/s\n",
            (double)buffer_bytes / gi, VEC, med, bw);
    printf("BUFFER_BYTES=%llu\n", buffer_bytes);
    printf("MEDIAN_MS=%.6f\n", med);
    printf("BANDWIDTH_GBPS=%.2f\n", bw);
    return 0;
}

#include <hip/hip_runtime.h>
#include <cstdio>
#include <cstdlib>
#include <vector>
#include <algorithm>
#include <cstdint>

#define HIP_CHECK(cmd) do { hipError_t e = (cmd); if (e != hipSuccess) { fprintf(stderr, "HIP error %s\n", hipGetErrorString(e)); exit(1); } } while(0)

// Variant A: float4 reads
__global__ void kernel_f4(const float4* __restrict__ in,
                          float* __restrict__ sink,
                          unsigned long long n_vec) {
    const unsigned long long tid =
        (unsigned long long)blockIdx.x * blockDim.x + threadIdx.x;
    const unsigned long long stride =
        (unsigned long long)gridDim.x * blockDim.x;
    float accum = 0.0f;
    for (unsigned long long i = tid; i < n_vec; i += stride) {
        float4 v = in[i];
        accum += v.x + v.y + v.z + v.w;
    }
    sink[tid] = accum;
}

// Variant B: float reads
__global__ void kernel_f(const float* __restrict__ in,
                          float* __restrict__ sink,
                          unsigned long long n) {
    const unsigned long long tid =
        (unsigned long long)blockIdx.x * blockDim.x + threadIdx.x;
    const unsigned long long stride =
        (unsigned long long)gridDim.x * blockDim.x;
    float accum = 0.0f;
    for (unsigned long long i = tid; i < n; i += stride) {
        accum += in[i];
    }
    sink[tid] = accum;
}

// Variant C: int4 reads (raw 16 bytes per load)
__global__ void kernel_i4(const int4* __restrict__ in,
                          int* __restrict__ sink,
                          unsigned long long n_vec) {
    const unsigned long long tid =
        (unsigned long long)blockIdx.x * blockDim.x + threadIdx.x;
    const unsigned long long stride =
        (unsigned long long)gridDim.x * blockDim.x;
    int accum = 0;
    for (unsigned long long i = tid; i < n_vec; i += stride) {
        int4 v = in[i];
        accum += v.x + v.y + v.z + v.w;
    }
    sink[tid] = accum;
}

// Variant D: float reads using __ldcg (cache global)
__global__ void kernel_ldcg(const float* __restrict__ in,
                          float* __restrict__ sink,
                          unsigned long long n) {
    const unsigned long long tid =
        (unsigned long long)blockIdx.x * blockDim.x + threadIdx.x;
    const unsigned long long stride =
        (unsigned long long)gridDim.x * blockDim.x;
    float accum = 0.0f;
    for (unsigned long long i = tid; i < n; i += stride) {
        accum += __ldcg(&in[i]);
    }
    sink[tid] = accum;
}

int main(int argc, char** argv) {
    HIP_CHECK(hipSetDevice(0));
    int VARIANT = (argc > 1) ? atoi(argv[1]) : 1;
    unsigned long long buffer_bytes = 4ULL << 30;
    void* d_in; float* d_sink;
    HIP_CHECK(hipMalloc(&d_in, (size_t)buffer_bytes));
    HIP_CHECK(hipMalloc(&d_sink, 4ULL << 20));
    HIP_CHECK(hipMemset(d_in, 0xab, (size_t)buffer_bytes));

    const int blocks = 1024, threads = 256;

    auto launch = [&]() {
        switch (VARIANT) {
            case 1: hipLaunchKernelGGL(kernel_f4, dim3(blocks), dim3(threads), 0, 0, (const float4*)d_in, d_sink, buffer_bytes/16); break;
            case 2: hipLaunchKernelGGL(kernel_f,  dim3(blocks), dim3(threads), 0, 0, (const float*)d_in,    d_sink, buffer_bytes/4);  break;
            case 3: hipLaunchKernelGGL(kernel_i4, dim3(blocks), dim3(threads), 0, 0, (const int4*)d_in,     (int*)d_sink, buffer_bytes/16); break;
            case 4: hipLaunchKernelGGL(kernel_ldcg, dim3(blocks), dim3(threads), 0, 0, (const float*)d_in,    d_sink, buffer_bytes/4); break;
        }
    };

    for (int i = 0; i < 10; ++i) launch();
    HIP_CHECK(hipDeviceSynchronize());

    const int N = 50;
    std::vector<float> t(N);
    hipEvent_t s, e;
    hipEventCreate(&s); hipEventCreate(&e);
    for (int i = 0; i < N; ++i) {
        hipEventRecord(s);
        launch();
        hipEventRecord(e);
    }
    HIP_CHECK(hipDeviceSynchronize());
    for (int i = 0; i < N; ++i) hipEventElapsedTime(&t[i], s, e);
    std::sort(t.begin(), t.end());
    float med = t[N/2];
    double bw = (double)buffer_bytes / (med * 1e-3) / 1e9;
    fprintf(stderr, "variant=%d  median=%.4f ms  bw=%.2f GB/s\n", VARIANT, med, bw);
    printf("BUFFER_BYTES=%llu\n", buffer_bytes);
    printf("MEDIAN_MS=%.6f\n", med);
    printf("BANDWIDTH_GBPS=%.2f\n", bw);
    return 0;
}

