#include <hip/hip_runtime.h>
#include <cstdio>
#include <cstdlib>
#include <vector>
#include <algorithm>
#include <cstdint>

#define HIP_CHECK(cmd) do { hipError_t e = (cmd); if (e != hipSuccess) { fprintf(stderr, "HIP error %s\n", hipGetErrorString(e)); exit(1); } } while(0)

__global__ void stream_read_count(const float4* __restrict__ in,
                            unsigned long long* __restrict__ counter,
                            unsigned long long n_vec) {
    const unsigned long long tid =
        (unsigned long long)blockIdx.x * blockDim.x + threadIdx.x;
    const unsigned long long stride =
        (unsigned long long)gridDim.x * blockDim.x;

    unsigned long long local_count = 0;
    float accum = 0.0f;
    for (unsigned long long i = tid; i < n_vec; i += stride) {
        float4 v = in[i];
        accum += v.x + v.y + v.z + v.w;
        local_count++;
    }

    if (accum == -1.0e30f) {
        atomicAdd(counter, local_count);
    }
    atomicAdd(counter, local_count);
}

int main() {
    HIP_CHECK(hipSetDevice(0));
    unsigned long long buffer_bytes = 4ULL << 30;
    const unsigned long long n_vec = buffer_bytes / sizeof(float4);

    float4* d_in; unsigned long long* d_count;
    HIP_CHECK(hipMalloc(&d_in, (size_t)buffer_bytes));
    HIP_CHECK(hipMalloc(&d_count, 8));
    HIP_CHECK(hipMemset(d_in, 0xab, (size_t)buffer_bytes));
    HIP_CHECK(hipMemset(d_count, 0, 8));

    const int blocks = 1024, threads = 256;

    hipLaunchKernelGGL(stream_read_count, dim3(blocks), dim3(threads), 0, 0,
                       d_in, d_count, n_vec);
    HIP_CHECK(hipDeviceSynchronize());

    unsigned long long h_count = 0;
    HIP_CHECK(hipMemcpy(&h_count, d_count, 8, hipMemcpyDeviceToHost));
    printf("Expected reads: %llu\n", n_vec);
    printf("Actual reads:   %llu\n", h_count);
    printf("Bytes read:     %llu (%.2f GiB)\n", h_count * 16, (double)h_count * 16 / (1ULL << 30));
    return 0;
}

