    hipEventCreate(&s); hipEventCreate(&e);
    for (int i = 0; i < N; ++i) {
        hipEventRecord(s);
        launch();
        hipEventRecord(e);
    }
    HIP_CHECK(hipDeviceSynchronize());
    for (int i = 0; i < N; ++i) hipEventElapsedTime(&t[i], s, e);
    std::sort(t.begin(), t.end());
    float med = t[N/2];
    // Effective bandwidth: iters * buffer_bytes / time
    double eff_bw = (double)ITERS * buffer_bytes / (med * 1e-3) / 1e9;
    double per_pass_bw = (double)buffer_bytes / (med * 1e-3 / ITERS) / 1e9;
    fprintf(stderr, "ITERS=%d  median=%.4f ms  effective_bw=%.2f GB/s\n", ITERS, med, eff_bw);
    printf("ITERS=%d\n", ITERS);
    printf("MEDIAN_MS=%.6f\n", med);
    printf("EFFECTIVE_BW_GBPS=%.2f\n", eff_bw);
    return 0;
}

