    for (int i = 0; i < 10; ++i) hipLaunchKernelGGL(stream_read, dim3(blocks), dim3(threads), 0, 0, d_in, d_sink, n_vec);
    HIP_CHECK(hipDeviceSynchronize());

    // Try various timing approaches
    const int N = 50;

    // Approach 1: per-iteration events
    {
        std::vector<float> t(N);
        std::vector<hipEvent_t> s(N), e(N);
        for (int i = 0; i < N; ++i) { hipEventCreate(&s[i]); hipEventCreate(&e[i]); }
        for (int i = 0; i < N; ++i) {
