        for (int i = 0; i < N; ++i) { hipEventDestroy(s[i]); hipEventDestroy(e[i]); }
    }

    // Approach 2: total timing (1 pair)
    {
        hipEvent_t s, e;
        hipEventCreate(&s); hipEventCreate(&e);
        hipEventRecord(s);
        for (int i = 0; i < N; ++i) {
            hipLaunchKernelGGL(stream_read, dim3(blocks), dim3(threads), 0, 0, d_in, d_sink, n_vec);
        }
        hipEventRecord(e);
        hipDeviceSynchronize();
        float total;
        hipEventElapsedTime(&total, s, e);
        fprintf(stderr, "Approach 2 (1 pair, N kernels): total=%.4f ms  per_kernel=%.4f ms\n", total, total/N);
        hipEventDestroy(s); hipEventDestroy(e);
    }

    // Approach 3: per-iter events with sync after each
    {
        std::vector<float> t(N);
        for (int i = 0; i < N; ++i) {
            hipEvent_t s, e;
            hipEventCreate(&s); hipEventCreate(&e);
            hipEventRecord(s);
            hipLaunchKernelGGL(stream_read, dim3(blocks), dim3(threads), 0, 0, d_in, d_sink, n_vec);
            hipEventRecord(e);
