    #pragma unroll 1
    for (unsigned long long i = tid; i < n_vec; i += stride) {
        float4 v = in[i];
        accum += v.x + v.y + v.z + v.w;
    }
    sink[tid] = accum;
}

double run_loop(int N, hipStream_t stream, float4* d_in, float* d_sink, unsigned long long n_vec,
                int blocks, int threads, bool use_stream) {
    hipEvent_t start, stop;
    HIP_CHECK(hipEventCreate(&start));
    HIP_CHECK(hipEventCreate(&stop));

    HIP_CHECK(hipEventRecord(start, stream));
    for (int i = 0; i < N; ++i) {
        if (use_stream) {
            hipLaunchKernelGGL(stream_read, dim3(blocks), dim3(threads), 0, stream,
                               d_in, d_sink, n_vec);
        } else {
            hipLaunchKernelGGL(empty_kernel, dim3(1), dim3(1), 0, stream);
        }
    }
    HIP_CHECK(hipEventRecord(stop, stream));
    HIP_CHECK(hipEventSynchronize(stop));
    float total_ms = 0.0f;
    HIP_CHECK(hipEventElapsedTime(&total_ms, start, stop));
    HIP_CHECK(hipEventDestroy(start));
    HIP_CHECK(hipEventDestroy(stop));
    return (double)total_ms;
}

int main() {
    HIP_CHECK(hipSetDevice(0));
    const unsigned long long buffer_bytes = 4ULL << 30;
    const unsigned long long n_vec = buffer_bytes / sizeof(float4);
    float4* d_in; float* d_sink;
    HIP_CHECK(hipMalloc(&d_in, (size_t)buffer_bytes));
    HIP_CHECK(hipMalloc(&d_sink, 4ULL << 20));
    HIP_CHECK(hipMemset(d_in, 0xab, (size_t)buffer_bytes));

    const int blocks = 1024, threads = 256;
    const int N = 50;

    // Warm up
    for (int i = 0; i < 20; ++i) hipLaunchKernelGGL(stream_read, dim3(blocks), dim3(threads), 0, 0, d_in, d_sink, n_vec);
    HIP_CHECK(hipDeviceSynchronize());

    hipStream_t stream;
    hipStreamCreate(&stream);

    double t_stream = run_loop(N, stream, d_in, d_sink, n_vec, blocks, threads, true);
    double t_empty = run_loop(N, stream, d_in, d_sink, n_vec, blocks, threads, false);

    double per_kernel_corrected = (t_stream - t_empty) / N;
    double per_kernel_raw = t_stream / N;
    double bw_corrected = (double)buffer_bytes / (per_kernel_corrected * 1e-3) / 1e9;
    double bw_raw = (double)buffer_bytes / (per_kernel_raw * 1e-3) / 1e9;

    fprintf(stderr, "raw: total=%.4f ms  per_kernel=%.4f ms  bw=%.2f GB/s\n", t_stream, per_kernel_raw, bw_raw);
    fprintf(stderr, "empty: total=%.4f ms  per_kernel_overhead=%.4f ms\n", t_empty, t_empty/N);
    fprintf(stderr, "corrected: per_kernel=%.4f ms  bw=%.2f GB/s\n", per_kernel_corrected, bw_corrected);
    return 0;
}

#include <hip/hip_runtime.h>
#include <cstdio>
#include <cstdlib>
#include <vector>
#include <algorithm>
#include <cstdint>

#define HIP_CHECK(cmd)                                                        \
    do {                                                                      \
        hipError_t e = (cmd);                                                 \
        if (e != hipSuccess) {                                                \
            fprintf(stderr, "HIP error %d (%s) at %s:%d for %s\n",            \
                    (int)e, hipGetErrorString(e), __FILE__, __LINE__, #cmd);  \
            exit(1);                                                          \
        }                                                                     \
    } while (0)

// Read-only streaming kernel: each thread sweeps the whole buffer with a
// grid-stride loop using float4 loads.  The accumulator is unconditionally
// written to a per-thread slot in `sink` so the compiler cannot dead-code
// eliminate the loads.
__global__ void stream_read(const float4* __restrict__ in,
                            float* __restrict__ sink,
                            unsigned long long n_vec) {
    const unsigned long long tid =
        (unsigned long long)blockIdx.x * blockDim.x + threadIdx.x;
    const unsigned long long stride =
        (unsigned long long)gridDim.x * blockDim.x;

    float accum = 0.0f;
    #pragma unroll 1
    for (unsigned long long i = tid; i < n_vec; i += stride) {
        float4 v = in[i];
        accum += v.x + v.y + v.z + v.w;
    }
    sink[tid] = accum;
}

// Trivial "do nothing" kernel used to measure per-launch overhead so that
// we can subtract it from the timed streaming kernel runs.
__global__ void noop_kernel() {}

static double time_loop_with_events(int N, hipStream_t stream,
                                    float4* d_in, float* d_sink,
                                    unsigned long long n_vec,
                                    int blocks, int threads,
                                    bool do_streaming) {
    hipEvent_t start, stop;
    HIP_CHECK(hipEventCreate(&start));
    HIP_CHECK(hipEventCreate(&stop));

    HIP_CHECK(hipEventRecord(start, stream));
    for (int i = 0; i < N; ++i) {
        if (do_streaming) {
            hipLaunchKernelGGL(stream_read, dim3(blocks), dim3(threads),
                               0, stream, d_in, d_sink, n_vec);
        } else {
            hipLaunchKernelGGL(noop_kernel, dim3(1), dim3(1), 0, stream);
        }
    }
    HIP_CHECK(hipEventRecord(stop, stream));
    HIP_CHECK(hipEventSynchronize(stop));
    float total_ms = 0.0f;
    HIP_CHECK(hipEventElapsedTime(&total_ms, start, stop));
    HIP_CHECK(hipEventDestroy(start));
    HIP_CHECK(hipEventDestroy(stop));
    return (double)total_ms;
}

int main() {
    HIP_CHECK(hipSetDevice(0));

    // 4 GiB working set:  far above any plausible L2 on MI35X (HBM3e capacity
    // is hundreds of GB; L2 is small) so every pass is forced to hit HBM.
    const unsigned long long buffer_bytes = 4ULL << 30;          // 4 GiB
    const unsigned long long n_vec = buffer_bytes / sizeof(float4);

    float4* d_in = nullptr;
    float*  d_sink = nullptr;
    HIP_CHECK(hipMalloc(&d_in,   (size_t)buffer_bytes));
    HIP_CHECK(hipMalloc(&d_sink, (size_t)(4ULL << 20)));

    // Touch the buffer so the GPU actually pages it in before timing.
    HIP_CHECK(hipMemset(d_in, 0xab, (size_t)buffer_bytes));
    HIP_CHECK(hipMemset(d_sink, 0, (size_t)(4ULL << 20)));

    const int blocks  = 1024;
    const int threads = 256;

    hipStream_t stream;
    HIP_CHECK(hipStreamCreate(&stream));

    // Warm up: bring clocks to steady state, fill I-cache, and pay any
    // first-touch / page-in costs.
    for (int i = 0; i < 20; ++i) {
        hipLaunchKernelGGL(stream_read, dim3(blocks), dim3(threads),
                           0, stream, d_in, d_sink, n_vec);
    }
    HIP_CHECK(hipStreamSynchronize(stream));

    // Per-launch overhead can fluctuate run-to-run (PMC sampling, host-side
    // queueing, etc.).  Take the median of M independent measurements of
    // (N streaming launches) and (N empty launches) to get a robust estimate
    // of per-launch overhead, then subtract.
    const int M = 5;
    const int N = 50;
    std::vector<double> t_stream(M), t_empty(M);
    for (int rep = 0; rep < M; ++rep) {
        // Interleave streaming and empty to keep clocks/queues balanced.
        t_stream[rep] = time_loop_with_events(N, stream, d_in, d_sink,
                                              n_vec, blocks, threads, true);
        t_empty[rep]  = time_loop_with_events(N, stream, d_in, d_sink,
                                              n_vec, blocks, threads, false);
    }

    std::sort(t_stream.begin(), t_stream.end());
    std::sort(t_empty.begin(),  t_empty.end());
    const double med_stream_ms = t_stream[M / 2];
    const double med_empty_ms  = t_empty [M / 2];

    // Per-launch corrected streaming time: subtract the per-launch overhead
    // measured by the empty-kernel loop from the per-launch streaming time.
    const double per_launch_stream_ms = med_stream_ms / (double)N;
    const double per_launch_empty_ms  = med_empty_ms  / (double)N;
    const double per_kernel_ms        = per_launch_stream_ms - per_launch_empty_ms;

    const double gbps = (double)buffer_bytes / (per_kernel_ms * 1e-3) / 1e9;

    fprintf(stderr,
            "[bench] stream_total=%.4f ms  empty_total=%.4f ms  "
            "per_kernel=%.4f ms (corrected)  buffer=%.2f GiB\n",
            med_stream_ms, med_empty_ms, per_kernel_ms,
            (double)buffer_bytes / (double)(1ULL << 30));
    fprintf(stderr, "[bench] HBM read bandwidth = %.2f GB/s\n", gbps);

    printf("HBM_BANDWIDTH_GBPS=%.2f\n", gbps);
    printf("buffer_bytes=%llu\n", buffer_bytes);

    HIP_CHECK(hipStreamDestroy(stream));
    HIP_CHECK(hipFree(d_in));
    HIP_CHECK(hipFree(d_sink));
    return 0;
}

