        if (e != hipSuccess) {                                                \
            fprintf(stderr, "HIP error %d (%s) at %s:%d for %s\n",            \
                    (int)e, hipGetErrorString(e), __FILE__, __LINE__, #cmd);  \
            exit(1);                                                          \
        }                                                                     \
    } while (0)

// Read-only streaming kernel with internal GPU-side timing.  Each launch
// records the wall-clock64() value at the start and end of thread 0; the
// delta in nanoseconds is written to a global slot for the host to read.
// The accumulator is unconditionally written to `sink` to prevent the
// compiler from dead-code-eliminating the loads.
__global__ void stream_read(const float4* __restrict__ in,
                            float* __restrict__ sink,
                            unsigned long long n_vec,
                            unsigned long long* __restrict__ t_out) {
    const unsigned long long tid =
        (unsigned long long)blockIdx.x * blockDim.x + threadIdx.x;
    const unsigned long long stride =
        (unsigned long long)gridDim.x * blockDim.x;

    // All threads wait briefly so thread 0's start time approximates the
    // kernel start; using threadfence + atomics would be over-engineered.
    unsigned long long t0 = (unsigned long long)wall_clock64();

    float accum = 0.0f;
    #pragma unroll 1
    for (unsigned long long i = tid; i < n_vec; i += stride) {
        float4 v = in[i];
        accum += v.x + v.y + v.z + v.w;
    }
    sink[tid] = accum;

