    HIP_CHECK(hipMemset(d_done, 0, sizeof(unsigned int)));
    HIP_CHECK(hipMemset(d_end_t, 0, sizeof(unsigned long long)));

    const int blocks = 1024, threads = 256;
    for (int i = 0; i < 20; ++i) hipLaunchKernelGGL(stream_read, dim3(blocks), dim3(threads), 0, 0, d_in, d_sink, n_vec, d_done, d_end_t);
