__device__ unsigned int g_done = 0;
__device__ unsigned long long g_end_cycles = 0;
__device__ unsigned long long g_start_cycles = 0;

__global__ void stream_read(const float4* __restrict__ in,
                            float* __restrict__ sink,
                            unsigned long long n_vec,
                            unsigned int* __restrict__ done,
                            unsigned long long* __restrict__ start_cyc,
                            unsigned long long* __restrict__ end_cyc) {
    const unsigned long long tid =
        (unsigned long long)blockIdx.x * blockDim.x + threadIdx.x;
    const unsigned long long stride =
        (unsigned long long)gridDim.x * blockDim.x;

    // First thread records start time
    if (blockIdx.x == 0 && threadIdx.x == 0) {
        *start_cyc = clock64();
    }

    float accum = 0.0f;
    #pragma unroll 1
    for (unsigned long long i = tid; i < n_vec; i += stride) {
        float4 v = in[i];
        accum += v.x + v.y + v.z + v.w;
    }
    sink[tid] = accum;

    __threadfence();
    unsigned int prev = atomicAdd(done, 1);
    unsigned int total_threads = gridDim.x * blockDim.x;
    if (prev == total_threads - 1) {
        // I'm the last thread to finish
        *end_cyc = clock64();
    }
}

int main() {
    HIP_CHECK(hipSetDevice(0));
    const unsigned long long buffer_bytes = 4ULL << 30;
    const unsigned long long n_vec = buffer_bytes / sizeof(float4);

    float4* d_in; float* d_sink;
    unsigned int* d_done;
    unsigned long long* d_start, *d_end;
    HIP_CHECK(hipMalloc(&d_in, (size_t)buffer_bytes));
    HIP_CHECK(hipMalloc(&d_sink, 4ULL << 20));
    HIP_CHECK(hipMalloc(&d_done, sizeof(unsigned int)));
    HIP_CHECK(hipMalloc(&d_start, sizeof(unsigned long long)));
    HIP_CHECK(hipMalloc(&d_end, sizeof(unsigned long long)));
    HIP_CHECK(hipMemset(d_in, 0xab, (size_t)buffer_bytes));

    const int blocks = 1024, threads = 256;

    // Warmup
    for (int i = 0; i < 10; ++i) hipLaunchKernelGGL(stream_read, dim3(blocks), dim3(threads), 0, 0, d_in, d_sink, n_vec, d_done, d_start, d_end);
    HIP_CHECK(hipDeviceSynchronize());

    // Get clock rate from device properties
    hipDeviceProp_t p;
    HIP_CHECK(hipGetDeviceProperties(&p, 0));
    double clock_ghz = p.clockRate / 1e6;  // kHz -> GHz
    fprintf(stderr, "GPU clock rate: %.3f GHz\n", clock_ghz);

    const int N = 50;
    unsigned long long h_start, h_end;
    for (int i = 0; i < N; ++i) {
        HIP_CHECK(hipMemset(d_done, 0, sizeof(unsigned int)));
        hipLaunchKernelGGL(stream_read, dim3(blocks), dim3(threads), 0, 0, d_in, d_sink, n_vec, d_done, d_start, d_end);
        HIP_CHECK(hipDeviceSynchronize());
        HIP_CHECK(hipMemcpy(&h_start, d_start, sizeof(unsigned long long), hipMemcpyDeviceToHost));
        HIP_CHECK(hipMemcpy(&h_end, d_end, sizeof(unsigned long long), hipMemcpyDeviceToHost));
        unsigned long long cycles = h_end - h_start;
        double kernel_ms = (double)cycles / clock_ghz / 1e6;
        if (i < 5) fprintf(stderr, "iter=%d  cycles=%llu  kernel_ms=%.4f\n", i, cycles, kernel_ms);
    }
    return 0;
}

