// Read-only streaming kernel: every thread sweeps the whole buffer with a
// grid-stride loop using float4 loads.  The accumulator is unconditionally
// written to a per-thread slot of `sink` so the compiler cannot prove the
// loads are unused and dead-code-eliminate them.
__global__ void stream_read(const float4* __restrict__ in,
                            float* __restrict__ sink,
                            unsigned long long n_vec) {
    const unsigned long long tid =
        (unsigned long long)blockIdx.x * blockDim.x + threadIdx.x;
    const unsigned long long stride =
        (unsigned long long)gridDim.x * blockDim.x;

    float accum = 0.0f;
    #pragma unroll 1
    for (unsigned long long i = tid; i < n_vec; i += stride) {
        float4 v = in[i];
        accum += v.x + v.y + v.z + v.w;
    }
    sink[tid] = accum;
}

// Tiny no-op kernel used to measure the per-launch overhead contributed by
// the runtime and the profiling tool.  Under rocprofv3 each hipEventRecord
// call sits behind the PMC instrumentation layer and adds a noticeable
// per-call latency (tens of microseconds).  Subtracting the per-launch
// overhead measured with this no-op kernel from the per-launch time of the
// streaming kernel isolates the streaming kernel's actual GPU duration,
// which is what rocprofv3 reports in its kernel_dispatch table.
