__global__ void stream_ldcs(const float4* __restrict__ in,
                            float* __restrict__ sink,
                            unsigned long long n_vec) {
    const unsigned long long tid = (unsigned long long)blockIdx.x * blockDim.x + threadIdx.x;
    const unsigned long long stride = (unsigned long long)gridDim.x * blockDim.x;
    float accum = 0.0f;
    for (unsigned long long i = tid; i < n_vec; i += stride) {
        float4 v = __ldcs(&in[i]);  // streaming load
        accum += v.x + v.y + v.z + v.w;
    }
    sink[tid] = accum;
}

int main() {
    HIP_CHECK(hipSetDevice(0));
    unsigned long long buffer_bytes = 4ULL << 30;
    unsigned long long n_vec = buffer_bytes / sizeof(float4);

    float4* d_in; float* d_sink;
