    HIP_CHECK(hipMalloc(&d_sink, 4ULL << 20));
    HIP_CHECK(hipMemset(d_in, 0xab, (size_t)buffer_bytes));

    const int blocks = 1024, threads = 256;
    for (int i = 0; i < 20; ++i) hipLaunchKernelGGL(stream_ldcs, dim3(blocks), dim3(threads), 0, 0, d_in, d_sink, n_vec);
    HIP_CHECK(hipDeviceSynchronize());

    const int N = 50;
    hipEvent_t s, e;
    hipEventCreate(&s); hipEventCreate(&e);
    hipEventRecord(s);
    for (int i = 0; i < N; ++i) hipLaunchKernelGGL(stream_ldcs, dim3(blocks), dim3(threads), 0, 0, d_in, d_sink, n_vec);
    hipEventRecord(e);
    HIP_CHECK(hipDeviceSynchronize());
    float ms;
    hipEventElapsedTime(&ms, s, e);
    double bw = buffer_bytes / (ms/N * 1e-3) / 1e9;
    fprintf(stderr, "ldcs: per_kernel=%.4f ms  bw=%.2f GB/s\n", ms/N, bw);
    return 0;
}
